const express = require('express');
const http = require('http');
const WebSocket = require('ws');
const complianceChecker = require('./complianceChecker');
const mlModel = require('./mlModel');
const db = require('./database');

const app = express();
const server = http.createServer(app);
const wss = new WebSocket.Server({ server });

wss.on('connection', (ws) => {
    console.log('Client connected');

    ws.on('message', async (message) => {
        try {
            const contentMetadata = JSON.parse(message);
            const ruleViolations = complianceChecker.check(contentMetadata);
            const mlViolations = await mlModel.analyze(contentMetadata);

            const allViolations = [...ruleViolations, ...mlViolations];

            if (allViolations.length > 0) {
                db.saveComplianceResult(contentMetadata, allViolations);
                ws.send(JSON.stringify({
                    type: 'ALERT',
                    violations: allViolations,
                    recommendations: generateRecommendations(allViolations)
                }));
            }
        } catch (error) {
            console.error('Error processing message:', error);
            ws.send(JSON.stringify({
                type: 'ERROR',
                message: 'Failed to process compliance check'
            }));
        }
    });

    ws.on('close', () => {
        console.log('Client disconnected');
    });
});

