from django.shortcuts import render, get_object_or_404, redirect
from .models import DocumentTemplate
from .forms import DocumentTemplateForm
from django.contrib import messages

def list_templates(request):
    templates = DocumentTemplate.objects.all()
    return render(request, 'template_manager/list_templates.html', {'templates': templates})

def create_template(request):
    if request.method == 'POST':
        form = DocumentTemplateForm(request.POST)
        if form.is_valid():
            form.save()
            messages.success(request, 'Template created successfully.')
            return redirect('list_templates')
    else:
        form = DocumentTemplateForm()
    return render(request, 'template_manager/create_template.html', {'form': form})

def edit_template(request, template_id):
    template = get_object_or_404(DocumentTemplate, id=template_id)
    if request.method == 'POST':
        form = DocumentTemplateForm(request.POST, instance=template)
        if form.is_valid():
            form.save()
            messages.success(request, 'Template updated successfully.')
            return redirect('list_templates')
    else:
        form = DocumentTemplateForm(instance=template)
    return render(request, 'template_manager/edit_template.html', {'form': form})

def delete_template(request, template_id):
    template = get_object_or_404(DocumentTemplate, id=template_id)
    if request.method == 'POST':
        template.delete()
        messages.success(request, 'Template deleted successfully.')
        return redirect('list_templates')
    return render(request, 'template_manager/confirm_delete.html', {'template': template})

