import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { fetchData } from '../utils/api';

// ReferralChart component to display referral data using D3.js
const ReferralChart = () => {
  const chartRef = useRef();

  useEffect(() => {
    const svg = d3.select(chartRef.current)
      .attr('width', '100%')
      .attr('height', 300);

    const updateChart = async () => {
      const data = await fetchData('/api/referral-data'); // Fetch data from the server
      // Clear existing content
      svg.selectAll('*').remove();

      // Set up scales and axes
      const xScale = d3.scaleBand().range([0, 400]).domain(data.map(d => d.name)).padding(0.4);
      const yScale = d3.scaleLinear().range([300, 0]).domain([0, d3.max(data, d => d.value)]);

      // Bind data and create bars
      svg.selectAll('.bar')
        .data(data)
        .enter()
        .append('rect')
        .attr('class', 'bar')
        .attr('x', d => xScale(d.name))
        .attr('y', d => yScale(d.value))
        .attr('width', xScale.bandwidth())
        .attr('height', d => 300 - yScale(d.value))
        .attr('fill', '#69b3a2');

      // Add x-axis
      svg.append('g')
        .attr('transform', 'translate(0,300)')
        .call(d3.axisBottom(xScale));

      // Add y-axis
      svg.append('g')
        .call(d3.axisLeft(yScale));
    };

    // Initial chart setup
    updateChart();

    // Polling mechanism to update chart every 60 seconds
    const interval = setInterval(updateChart, 60000);
    return () => clearInterval(interval);

  }, []);

  return <svg ref={chartRef}></svg>;
};

export default ReferralChart;

