@incentive_blueprint.route('/', methods=['POST'])
def create_incentive():
    data = request.json
    new_incentive = IncentiveProgram(
        name=data.get('name'),
        description=data.get('description'),
        commission_tier=data.get('commission_tier'),
        bonus_rewards=data.get('bonus_rewards'),
        performance_metrics=data.get('performance_metrics')
    )
    db.session.add(new_incentive)
    db.session.commit()
    return jsonify(new_incentive.to_dict()), 201

@incentive_blueprint.route('/<int:id>', methods=['PUT'])
def update_incentive(id):
    data = request.json
    incentive = IncentiveProgram.query.get_or_404(id)
    incentive.name = data.get('name', incentive.name)
    incentive.description = data.get('description', incentive.description)
    incentive.commission_tier = data.get('commission_tier', incentive.commission_tier)
    incentive.bonus_rewards = data.get('bonus_rewards', incentive.bonus_rewards)
    incentive.performance_metrics = data.get('performance_metrics', incentive.performance_metrics)
    db.session.commit()
