// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/// @title RevenueShare
/// @dev A contract for automated revenue sharing among content creators and partners
contract RevenueShare {
    address public owner;
    struct Partner {
        address wallet;
        uint256 sharePercentage; // Share percentage (e.g., 25 for 25%)
    }

    Partner[] public partners;
    uint256 public totalShares;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    event RevenueDistributed(uint256 amount, uint256 timestamp);

    /// @notice Constructor sets the initial owner
    constructor() {
        owner = msg.sender;
    }

    /// @notice Add a new partner to the revenue share agreement
    /// @param _wallet The wallet address of the partner
    /// @param _sharePercentage The percentage share of the partner
    function addPartner(address _wallet, uint256 _sharePercentage) external onlyOwner {
        require(_sharePercentage > 0 && _sharePercentage <= 100, "Invalid share percentage");
        totalShares += _sharePercentage;
        require(totalShares <= 100, "Total shares exceed 100%");
        partners.push(Partner(_wallet, _sharePercentage));
    }

    /// @notice Distribute revenue based on predefined shares
    function distributeRevenue() external payable onlyOwner {
        require(msg.value > 0, "No revenue to distribute");
        for (uint256 i = 0; i < partners.length; i++) {
            uint256 shareAmount = (msg.value * partners[i].sharePercentage) / 100;
            payable(partners[i].wallet).transfer(shareAmount);
        }
        emit RevenueDistributed(msg.value, block.timestamp);
    }
}

