import java.util.Map;

@Service
public class ReportService {

    @Autowired
    private ReportRepository reportRepository;

    @Autowired
    private JavaMailSender mailSender;

    // Generate report based on template and parameters
    public void generateReport(String templateName, Map<String, Object> parameters, String email) throws Exception {
        // Fetch data from the repository
        List<Object> reportData = reportRepository.fetchReportData(parameters);

        // Load Jasper template
        JasperReport jasperReport = JasperCompileManager.compileReport(new ClassPathResource("templates/" + templateName + ".jrxml").getInputStream());

        // Fill the report with data
        JRBeanCollectionDataSource dataSource = new JRBeanCollectionDataSource(reportData);
        JasperPrint jasperPrint = JasperFillManager.fillReport(jasperReport, parameters, dataSource);

        // Export the report to a PDF file
        String outputPath = "reports/" + templateName + "_" + System.currentTimeMillis() + ".pdf";
        JasperExportManager.exportReportToPdfFile(jasperPrint, outputPath);

        // Send the report via email
        sendEmailWithAttachment(email, outputPath);

        // Archive the report
        archiveReport(outputPath, templateName, parameters);
    }

    // Send email with attached report
    private void sendEmailWithAttachment(String email, String filePath) throws MessagingException {
        MimeMessage message = mailSender.createMimeMessage();
        MimeMessageHelper helper = new MimeMessageHelper(message, true);
        helper.setTo(email);
        helper.setSubject("Your Requested Report");
        helper.setText("Please find attached the report you requested.");
        helper.addAttachment("Report.pdf", new File(filePath));
        mailSender.send(message);
    }

