// utils/streamHandler.js

const axios = require('axios');

/**
 * Handles the distribution of stream data to various platforms.
 * @param {Object} data - Stream data from the client.
 * @param {Object} platformConfig - Configuration for each platform.
 * @returns {Promise}
 */
async function handleStream(data, platformConfig) {
  try {
    await Promise.all([
      uploadToYouTube(data, platformConfig.youtube),
      uploadToTwitch(data, platformConfig.twitch),
      uploadToFacebook(data, platformConfig.facebook)
    ]);
  } catch (error) {
    console.error('Error in handleStream:', error);
    throw error;
  }
}

/**
 * Uploads stream data to YouTube.
 * @param {Object} data - Stream data.
 * @param {Object} config - YouTube configuration.
 * @returns {Promise}
 */
async function uploadToYouTube(data, config) {
  try {
    const response = await axios.post(config.streamUrl, data, {
      headers: {
        Authorization: `Bearer ${config.apiKey}`,
        'Content-Type': 'application/json'
      }
    });
    console.log('YouTube response:', response.data);
  } catch (error) {
    console.error('YouTube upload error:', error.response.data);
    throw error;
  }
}

/**
 * Uploads stream data to Twitch.
 * @param {Object} data - Stream data.
 * @param {Object} config - Twitch configuration.
 * @returns {Promise}
 */
async function uploadToTwitch(data, config) {
  try {
    const response = await axios.post(config.streamUrl, data, {
      headers: {
        'Client-ID': config.clientId,
        'Authorization': `Bearer ${config.accessToken}`,
        'Content-Type': 'application/json'
      }
    });
    console.log('Twitch response:', response.data);
  } catch (error) {
    console.error('Twitch upload error:', error.response.data);
    throw error;
  }
}

/**
 * Uploads stream data to Facebook.
 * @param {Object} data - Stream data.
 * @param {Object} config - Facebook configuration.
 * @returns {Promise}
 */
async function uploadToFacebook(data, config) {
  try {
    const response = await axios.post(config.streamUrl, data, {
      params: {
        access_token: config.accessToken
      },
      headers: {
        'Content-Type': 'application/json'
      }
    });
    console.log('Facebook response:', response.data);
  } catch (error) {
    console.error('Facebook upload error:', error.response.data);
    throw error;
  }
}

module.exports = {
  handleStream
};

