import React, { useState, useEffect } from 'react';
import ViewerEngagementChart from './ViewerEngagementChart';
import RevenueMetricsChart from './RevenueMetricsChart';
import PerformanceIndicators from './PerformanceIndicators';
import { fetchInitialData, subscribeToUpdates } from '../services/api';
import '../styles/dashboard.css';

const Dashboard = () => {
  const [sessionData, setSessionData] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch initial data
    fetchInitialData().then(data => {
      setSessionData(data);
      setLoading(false);
    });

    // Subscribe to real-time updates
    const unsubscribe = subscribeToUpdates(newData => {
      setSessionData(prevData => [...prevData, ...newData]);
    });

    // Cleanup on component unmount
    return () => unsubscribe();
  }, []);

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <div className="dashboard">
      <ViewerEngagementChart data={sessionData} />
      <RevenueMetricsChart data={sessionData} />
      <PerformanceIndicators data={sessionData} />
    </div>
  );
};

export default Dashboard;

