import stripe
import paypalrestsdk
import os
from config import Config

class PaymentProcessor:
    def __init__(self):
        # Configure Stripe
        stripe.api_key = Config.STRIPE_SECRET_KEY

        # Configure PayPal SDK
        paypalrestsdk.configure({
            "mode": "sandbox",  # or "live"
            "client_id": Config.PAYPAL_CLIENT_ID,
            "client_secret": Config.PAYPAL_CLIENT_SECRET
        })

    def process_payment(self, user_id, amount, currency, payment_method):
        if payment_method == 'stripe':
            return self.process_stripe_payment(user_id, amount, currency)
        elif payment_method == 'paypal':
            return self.process_paypal_payment(user_id, amount, currency)
        else:
            raise ValueError("Unsupported payment method")

    def process_stripe_payment(self, user_id, amount, currency):
        try:
            charge = stripe.Charge.create(
                amount=int(amount * 100),  # Stripe expects amount in cents
                currency=currency,
                source="tok_mastercard",  # Replace with actual payment source
                description=f"Charge for user {user_id}"
            )
            return charge.id
        except stripe.error.StripeError as e:
            raise Exception(f"Stripe payment failed: {e.user_message}")

    def process_paypal_payment(self, user_id, amount, currency):
        payment = paypalrestsdk.Payment({
            "intent": "sale",
            "payer": {
                "payment_method": "paypal"
            },
            "transactions": [{
                "amount": {
                    "total": f"{amount:.2f}",
                    "currency": currency
                },
                "description": f"Payment for user {user_id}"
            }],
            "redirect_urls": {
                "return_url": "http://localhost:5000/payment/execute",
                "cancel_url": "http://localhost:5000/"
            }
        })
        if payment.create():
            return payment.id
        else:
            raise Exception(f"PayPal payment failed: {payment.error}")

