from elasticsearch import Elasticsearch
from kafka import KafkaProducer
import json
from datetime import datetime

# Connect to Elasticsearch
es = Elasticsearch(['http://localhost:9200'])

# Connect to Kafka
producer = KafkaProducer(
    bootstrap_servers='localhost:9092',
    value_serializer=lambda v: json.dumps(v).encode('utf-8')
)

def check_compliance():
    # Search for contracts in Elasticsearch
    query = {
        "query": {
            "bool": {
                "filter": {
                    "range": {
                        "end_date": {"lte": datetime.now().strftime('%Y-%m-%d')}
                    }
                }
            }
        }
    }

    # Fetch contracts with potential compliance issues
    response = es.search(index="contracts", body=query)

    for contract in response['hits']['hits']:
        contract_data = contract['_source']
        if contract_data.get('compliance_status', True) is False:
            # Publish an alert to Kafka
            producer.send('compliance_alerts', {
                'contract_id': contract_data['contract_id'],
                'issue': 'Contract has expired or terms not met',
                'end_date': contract_data['end_date']
            })
            print(f"Alert sent for contract {contract_data['contract_id']}")

if __name__ == "__main__":
    check_compliance()

