package findom.analytics.producer;

import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.ProducerConfig;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.serialization.StringSerializer;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.util.Properties;
import java.util.Random;

public class SubscriptionEventProducer {

    private static final String TOPIC = "subscription-events";

    public static void main(String[] args) {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());

        KafkaProducer<String, String> producer = new KafkaProducer<>(props);
        ObjectMapper objectMapper = new ObjectMapper();
        Random random = new Random();

        try {
            for (int i = 0; i < 1000; i++) {
                SubscriptionEvent event = new SubscriptionEvent(
                    "user" + random.nextInt(100),
                    "platform" + random.nextInt(5),
                    random.nextInt(1000)
                );

                String eventString = objectMapper.writeValueAsString(event);
                producer.send(new ProducerRecord<>(TOPIC, event.getUserId(), eventString));
                System.out.println("Produced: " + eventString);

                Thread.sleep(1000);  // Simulate event generation delay
            }
        } catch (Exception e) {
            e.printStackTrace();
        } finally {
            producer.close();
        }
    }

    public static class SubscriptionEvent {
        private String userId;
        private String platform;
        private int amount;

        public SubscriptionEvent(String userId, String platform, int amount) {
            this.userId = userId;
            this.platform = platform;
            this.amount = amount;
        }

        public String getUserId() {
            return userId;
        }

        public String getPlatform() {
            return platform;
        }

        public int getAmount() {
            return amount;
        }
    }
}

