# stripe_integration.py
import stripe
from flask import jsonify, abort

# Initialize Stripe with API key
stripe.api_key = 'your_stripe_secret_key'

def create_stripe_session(amount, currency, success_url, cancel_url):
    try:
        session = stripe.checkout.Session.create(
            payment_method_types=['card'],
            line_items=[{
                'price_data': {
                    'currency': currency,
                    'product_data': {
                        'name': 'Subscription Service',
                    },
                    'unit_amount': amount,
                },
                'quantity': 1,
            }],
            mode='payment',
            success_url=success_url,
            cancel_url=cancel_url,
        )
        return session
    except Exception as e:
        raise Exception(f"Stripe Session creation failed: {str(e)}")

def handle_stripe_webhook(payload, sig_header):
    endpoint_secret = 'your_stripe_endpoint_secret'
    try:
        event = stripe.Webhook.construct_event(
            payload, sig_header, endpoint_secret
        )
        # Handle the event
        if event['type'] == 'checkout.session.completed':
            handle_checkout_session_completed(event['data']['object'])
        return event
    except ValueError as e:
        # Invalid payload
        raise Exception(f"Invalid payload: {str(e)}")
    except stripe.error.SignatureVerificationError as e:
        # Invalid signature
        raise Exception(f"Invalid signature: {str(e)}")

def handle_checkout_session_completed(session):
    # Logic to handle successful checkout session
    print(f"Checkout session completed: {session['id']}")

