const Invoice = require('../models/Invoice');
const PaymentService = require('../services/PaymentService');
const EmailService = require('../services/EmailService');

class BillingController {
  static async generateInvoice(req, res) {
    try {
      const { userId, auctionId, amount, userEmail } = req.body;
      const invoice = new Invoice({ userId, auctionId, amount });

      await invoice.save();
      await EmailService.sendInvoiceEmail(userEmail, invoice);

      res.status(201).json({ message: 'Invoice generated and email sent.', invoice });
    } catch (error) {
      res.status(500).json({ error: error.message });
    }
  }

  static async processPayment(req, res) {
    try {
      const { invoiceId } = req.params;
      const invoice = await Invoice.findById(invoiceId);

      if (!invoice) {
        return res.status(404).json({ error: 'Invoice not found' });
      }

      const paymentIntent = await PaymentService.processPayment(invoice);

      invoice.status = 'paid';
      await invoice.save();

      res.status(200).json({ message: 'Payment successful', paymentIntent });
    } catch (error) {
      res.status(500).json({ error: error.message });
    }
  }
}

module.exports = BillingController;

