    """

    @abstractmethod
    def create_payment(self, amount, currency, description, return_url, cancel_url):
        """
        Create a payment request.
        """
        pass

    @abstractmethod
    def execute_payment(self, payment_id, payer_id):
        """
        Execute a payment after user approval.
        """
        pass

    @abstractmethod
    def handle_webhook(self, request_data):
        """
        Handle webhook notifications from the payment provider.
        """
