from fastapi import APIRouter, HTTPException, Depends
from sqlalchemy.orm import Session
from database import get_db
from models import User, RewardHistory
from services import calculate_loyalty_level, add_loyalty_points

router = APIRouter()

@router.post("/earn_points/")
def earn_points(user_id: int, points: int, db: Session = Depends(get_db)):
    user = db.query(User).filter(User.id == user_id).first()
    if not user:
        raise HTTPException(status_code=404, detail="User not found")

    user.loyalty_points += points
    user.loyalty_level = calculate_loyalty_level(user.loyalty_points)
    db.commit()
