    if not user:
        raise HTTPException(status_code=404, detail="User not found")

    return {
        "username": user.username,
        "loyalty_points": user.loyalty_points,
        "loyalty_level": user.loyalty_level
    }

@router.post("/redeem_reward/")
def redeem_reward(user_id: int, reward_description: str, points: int, db: Session = Depends(get_db)):
    user = db.query(User).filter(User.id == user_id).first()
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    if user.loyalty_points < points:
        raise HTTPException(status_code=400, detail="Insufficient points")

    user.loyalty_points -= points
    db.add(RewardHistory(user_id=user_id, reward_description=reward_description, points_used=points))
    db.commit()
    return {"message": "Reward redeemed successfully"}

