from django.shortcuts import get_object_or_404
from django.http import JsonResponse
from django.views.decorators.http import require_POST
from .models import Auction, Bid
from django.db import transaction

@require_POST
def place_bid(request, auction_id):
    auction = get_object_or_404(Auction, id=auction_id)
    bid_amount = request.POST.get('bid_amount')
    user = request.user

    if auction.end_time < timezone.now():
        return JsonResponse({'error': 'Auction has ended'}, status=400)

    try:
        with transaction.atomic():
            highest_bid = auction.bids.first()
            if highest_bid and highest_bid.amount >= bid_amount:
                return JsonResponse({'error': 'Bid must be higher than current highest bid'}, status=400)

            new_bid = Bid.objects.create(auction=auction, bidder=user, amount=bid_amount)
            return JsonResponse({'success': 'Bid placed successfully'}, status=201)

    except Exception as e:
        return JsonResponse({'error': str(e)}, status=500)

