from flask import Flask, jsonify, request
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy.exc import IntegrityError
from werkzeug.exceptions import NotFound, BadRequest

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'postgresql://user:password@localhost/findom'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)

# Models
class Category(db.Model):
    __tablename__ = 'categories'
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(255), unique=True, nullable=False)

class Good(db.Model):
    __tablename__ = 'goods'
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(255), nullable=False)
    description = db.Column(db.Text)
    category_id = db.Column(db.Integer, db.ForeignKey('categories.id'), nullable=False)
    price = db.Column(db.Numeric(10, 2), nullable=False)
    stock = db.Column(db.Integer, nullable=False)
    created_at = db.Column(db.DateTime, default=db.func.current_timestamp())
    updated_at = db.Column(db.DateTime, default=db.func.current_timestamp(), onupdate=db.func.current_timestamp())

# Routes
@app.route('/goods', methods=['GET'])
def get_goods():
    goods = Good.query.all()
    return jsonify([{
        'id': good.id,
        'name': good.name,
        'description': good.description,
        'category_id': good.category_id,
        'price': str(good.price),
        'stock': good.stock
    } for good in goods])

@app.route('/goods/<int:good_id>', methods=['GET'])
def get_good(good_id):
    good = Good.query.get(good_id)
    if not good:
        raise NotFound("Good not found")
    return jsonify({
        'id': good.id,
        'name': good.name,
        'description': good.description,
        'category_id': good.category_id,
        'price': str(good.price),
        'stock': good.stock
    })

@app.route('/goods', methods=['POST'])
def create_good():
    data = request.json
    new_good = Good(
        name=data['name'],
        description=data.get('description'),
        category_id=data['category_id'],
        price=data['price'],
        stock=data['stock']
    )
    db.session.add(new_good)
    try:
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        raise BadRequest("Invalid data or duplicate entry")
    return jsonify({'id': new_good.id}), 201

@app.route('/goods/<int:good_id>', methods=['PUT'])
def update_good(good_id):
    data = request.json
    good = Good.query.get(good_id)
    if not good:
        raise NotFound("Good not found")

    good.name = data.get('name', good.name)
    good.description = data.get('description', good.description)
    good.category_id = data.get('category_id', good.category_id)
    good.price = data.get('price', good.price)
    good.stock = data.get('stock', good.stock)

    db.session.commit()
    return jsonify({'message': 'Good updated successfully'})

@app.route('/goods/<int:good_id>', methods=['DELETE'])
def delete_good(good_id):
    good = Good.query.get(good_id)
    if not good:
        raise NotFound("Good not found")

    db.session.delete(good)
    db.session.commit()
    return jsonify({'message': 'Good deleted successfully'})

# Error handlers
@app.errorhandler(NotFound)
def handle_not_found(e):
    return jsonify(error=str(e)), 404

@app.errorhandler(BadRequest)
def handle_bad_request(e):
    return jsonify(error=str(e)), 400

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)

