import requests
import time
import json

class OAuth2Manager:
    def __init__(self, client_id, client_secret, auth_url, token_url, redirect_uri, scope):
        self.client_id = client_id
        self.client_secret = client_secret
        self.auth_url = auth_url
        self.token_url = token_url
        self.redirect_uri = redirect_uri
        self.scope = scope
        self.access_token = None
        self.refresh_token = None
        self.token_expiry = None

    def authenticate_user(self):
        # Step 1: Direct user to authorization URL
        auth_request_url = f"{self.auth_url}?client_id={self.client_id}&redirect_uri={self.redirect_uri}&response_type=code&scope={self.scope}"
        print(f"Please go to this URL and authorize access: {auth_request_url}")

        # Step 2: User enters the authorization code after granting access
        auth_code = input("Enter the authorization code: ")

        # Step 3: Exchange authorization code for access token
        token_response = requests.post(self.token_url, data={
            'client_id': self.client_id,
            'client_secret': self.client_secret,
            'code': auth_code,
            'redirect_uri': self.redirect_uri,
            'grant_type': 'authorization_code'
        })

        token_data = token_response.json()
        self.access_token = token_data['access_token']
        self.refresh_token = token_data.get('refresh_token')
        self.token_expiry = time.time() + token_data['expires_in']
        self.save_tokens()

    def refresh_access_token(self):
        if self.refresh_token and time.time() > self.token_expiry:
            response = requests.post(self.token_url, data={
                'client_id': self.client_id,
                'client_secret': self.client_secret,
                'refresh_token': self.refresh_token,
                'grant_type': 'refresh_token'
            })

            if response.status_code == 200:
                token_data = response.json()
                self.access_token = token_data['access_token']
                self.token_expiry = time.time() + token_data['expires_in']
                self.save_tokens()
            else:
                raise Exception("Failed to refresh access token")

    def save_tokens(self):
        # Saves access and refresh tokens to a secure storage (e.g., encrypted database or file)
        with open('tokens.json', 'w') as f:
            json.dump({
                'access_token': self.access_token,
                'refresh_token': self.refresh_token,
                'token_expiry': self.token_expiry
            }, f)

    def load_tokens(self):
        # Loads tokens from storage if they exist
        try:
            with open('tokens.json', 'r') as f:
                token_data = json.load(f)
                self.access_token = token_data['access_token']
                self.refresh_token = token_data['refresh_token']
                self.token_expiry = token_data['token_expiry']
        except FileNotFoundError:
            pass

