import time
import threading

class RateLimitManager:
    def __init__(self, max_requests, time_window):
        self.max_requests = max_requests
        self.time_window = time_window
        self.lock = threading.Lock()
        self.request_times = []

    def can_make_request(self):
        with self.lock:
            current_time = time.time()
            self.request_times = [t for t in self.request_times if current_time - t < self.time_window]

            if len(self.request_times) < self.max_requests:
                self.request_times.append(current_time)
                return True
            else:
                return False

    def wait_for_slot(self):
        while not self.can_make_request():
            time.sleep(0.1)

# Example usage of RateLimitManager
if __name__ == "__main__":
    rate_limiter = RateLimitManager(max_requests=10, time_window=60)  # 10 requests per minute

    def make_request():
        rate_limiter.wait_for_slot()
        print(f"Request made at {time.time()}")

    # Simulate making API requests
    for _ in range(15):
        threading.Thread(target=make_request).start()

