    await page.goto(global.URL);
  });

  afterAll(async () => {
    await page.close();
  });

  test('Page loads within acceptable time', async () => {
    const navigationPromise = page.waitForNavigation();
    const startTime = new Date();
    await page.goto(global.URL);
    await navigationPromise;
    const endTime = new Date();
    const loadTime = endTime - startTime;
    console.log(`Page Load Time: ${loadTime}ms`);
    expect(loadTime).toBeLessThan(3000); // Expect page to load in under 3 seconds
  });

  test('Real-time content updates are functioning', async () => {
    await page.goto(`${global.URL}/interactive`);
    await page.waitForSelector('#interactive-content');
    const initialContent = await page.$eval('#interactive-content', el => el.textContent);
    await page.click('#update-button');
    await page.waitForFunction(
      (initialContent) => document.querySelector('#interactive-content').textContent !== initialContent,
      {},
      initialContent
    );
    const updatedContent = await page.$eval('#interactive-content', el => el.textContent);
    expect(updatedContent).not.toBe(initialContent);
  });

  test('User interface is responsive across screen sizes', async () => {
    const viewports = [
      { width: 1920, height: 1080 }, // Desktop
      { width: 1280, height: 720 },  // Tablet
      { width: 375, height: 667 }    // Mobile
    ];

    for (const viewport of viewports) {
      await page.setViewport(viewport);
      await page.goto(global.URL);
      const isResponsive = await page.evaluate(() => {
        const el = document.querySelector('body');
        return window.getComputedStyle(el).overflowX === 'hidden'; // Check for horizontal scroll
      });
      expect(isResponsive).toBe(true);
    }
  });
