const { google } = require('googleapis');
const analytics = google.analytics('v3');

// Configure the Google Analytics API client
async function initializeAnalytics() {
    const authClient = await authorize();
    google.options({ auth: authClient });
}

// Authorize with Google API credentials
async function authorize() {
    const auth = new google.auth.GoogleAuth({
        keyFile: 'path/to/your/service-account-file.json',
        scopes: ['https://www.googleapis.com/auth/analytics.readonly'],
    });
    return await auth.getClient();
}

// Fetch data from Google Analytics for specific metrics and dimensions
async function fetchAnalyticsData(viewId, startDate, endDate) {
    await initializeAnalytics();

    const response = await analytics.data.ga.get({
        'ids': `ga:${viewId}`,
        'start-date': startDate,
        'end-date': endDate,
        'metrics': 'ga:sessions,ga:users,ga:pageviews',
        'dimensions': 'ga:language,ga:country',
    });

    return response.data.rows;
}

module.exports = { fetchAnalyticsData };

