from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import List
import uvicorn
import sqlite3

# Define the FastAPI app
app = FastAPI()

# Define the database connection
DATABASE = "feedback.db"

# Define a Pydantic model for user feedback
class UserFeedback(BaseModel):
    user_id: str
    session_id: str
    feedback_text: str
    rating: int

# Initialize the database and create table if it doesn't exist
def init_db():
    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()
    cursor.execute("""
    CREATE TABLE IF NOT EXISTS feedback (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id TEXT NOT NULL,
        session_id TEXT NOT NULL,
        feedback_text TEXT NOT NULL,
        rating INTEGER NOT NULL,
        timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
    )""")
    conn.commit()
    conn.close()

# Endpoint to submit feedback
@app.post("/submit_feedback/")
async def submit_feedback(feedback: UserFeedback):
    try:
        conn = sqlite3.connect(DATABASE)
        cursor = conn.cursor()
        cursor.execute("""
        INSERT INTO feedback (user_id, session_id, feedback_text, rating)
        VALUES (?, ?, ?, ?)
        """, (feedback.user_id, feedback.session_id, feedback.feedback_text, feedback.rating))
        conn.commit()
        conn.close()
        return {"status": "success", "message": "Feedback submitted successfully"}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

# Endpoint to retrieve feedback for analysis
@app.get("/retrieve_feedback/")
async def retrieve_feedback() -> List[UserFeedback]:
    try:
        conn = sqlite3.connect(DATABASE)
        cursor = conn.cursor()
        cursor.execute("SELECT user_id, session_id, feedback_text, rating FROM feedback")
        rows = cursor.fetchall()
        conn.close()
        feedback_list = [UserFeedback(user_id=row[0], session_id=row[1], feedback_text=row[2], rating=row[3]) for row in rows]
        return feedback_list
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

# Initialize the database when the server starts
init_db()

# Run the application
if __name__ == "__main__":
    uvicorn.run(app, host="0.0.0.0", port=8000)

