import sqlite3
import pandas as pd
from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.cluster import KMeans
import matplotlib.pyplot as plt

DATABASE = "feedback.db"

def fetch_feedback_data():
    conn = sqlite3.connect(DATABASE)
    query = "SELECT feedback_text, rating FROM feedback"
    df = pd.read_sql_query(query, conn)
    conn.close()
    return df

def analyze_feedback():
    df = fetch_feedback_data()

    # Perform text vectorization
    vectorizer = TfidfVectorizer(stop_words='english', max_features=100)
    X = vectorizer.fit_transform(df['feedback_text'])

    # Clustering feedback for insights
    kmeans = KMeans(n_clusters=5, random_state=42)
    df['cluster'] = kmeans.fit_predict(X)

    # Plot the distribution of feedback clusters
    plt.figure(figsize=(10, 6))
    df['cluster'].value_counts().plot(kind='bar')
    plt.title('Feedback Clusters')
    plt.xlabel('Cluster')
    plt.ylabel('Number of Feedbacks')
    plt.show()

    # Calculate average rating per cluster
    avg_ratings = df.groupby('cluster')['rating'].mean()
    print("Average Ratings per Cluster:")
    print(avg_ratings)

if __name__ == "__main__":
    analyze_feedback()

