/**
 * Create a PayPal payment.
 * @param {Object} paymentData - The data related to the payment.
 * @returns {Promise<Object>} - The payment response from PayPal.
 */
function createPayment(paymentData) {
  return new Promise((resolve, reject) => {
    const payment = {
      intent: 'sale',
      payer: { payment_method: 'paypal' },
      transactions: [{
        amount: { total: paymentData.amount, currency: paymentData.currency },
        description: paymentData.description,
      }],
      redirect_urls: {
        return_url: paymentData.returnUrl,
        cancel_url: paymentData.cancelUrl,
      },
    };

    paypal.payment.create(payment, function (error, payment) {
      if (error) {
        console.error('Error creating PayPal payment:', error);
        return reject(new Error('PayPal payment creation failed.'));
      }
      resolve(payment);
    });
  });
}

