from flask import Flask, request, jsonify
from sqlalchemy import create_engine, Column, Integer, String, DateTime
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker
from datetime import datetime
import hashlib
import os

app = Flask(__name__)

# Database configuration
DATABASE_URL = os.getenv('DATABASE_URL', 'postgresql://username:password@localhost/findom_db')

# Set up SQLAlchemy
engine = create_engine(DATABASE_URL)
Base = declarative_base()
Session = sessionmaker(bind=engine)
session = Session()

# Define the Event model
class Event(Base):
    __tablename__ = 'events'
    id = Column(Integer, primary_key=True)
    category = Column(String, nullable=False)
    action = Column(String, nullable=False)
    label = Column(String)
    value = Column(Integer)
    timestamp = Column(DateTime, default=datetime.utcnow)
    user_id_hash = Column(String, nullable=False)

Base.metadata.create_all(engine)

@app.route('/api/track_event', methods=['POST'])
def track_event():
    data = request.json
    if not data or 'category' not in data or 'action' not in data:
        return jsonify({'error': 'Invalid event data'}), 400

    # Anonymize user information
    user_id = request.headers.get('X-User-Id', 'anonymous')
    user_id_hash = hashlib.sha256(user_id.encode()).hexdigest()

    # Create a new event record
    event = Event(
        category=data['category'],
        action=data['action'],
        label=data.get('label'),
        value=data.get('value'),
        user_id_hash=user_id_hash
    )

    # Store the event
    try:
        session.add(event)
        session.commit()
        return jsonify({'status': 'success'}), 200
    except Exception as e:
        session.rollback()
        app.logger.error(f"Error storing event: {e}")
        return jsonify({'error': 'Database error'}), 500

if __name__ == '__main__':
    app.run(debug=True)

