import java.util.concurrent.TimeUnit;

public class KafkaInteractionProducer {
    private static final String TOPIC = "user-interactions";
    private static final String BOOTSTRAP_SERVERS = "localhost:9092";

    public static void main(String[] args) {
        Properties properties = new Properties();
        properties.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, BOOTSTRAP_SERVERS);
        properties.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        properties.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());

        KafkaProducer<String, String> producer = new KafkaProducer<>(properties);

        // Simulate user interaction data
        try {
            while (true) {
                String userId = "user" + new Random().nextInt(1000);
                String interaction = "interaction_type_" + new Random().nextInt(10);

                String message = String.format("{\"userId\":\"%s\", \"interaction\":\"%s\"}", userId, interaction);
                ProducerRecord<String, String> record = new ProducerRecord<>(TOPIC, userId, message);

                producer.send(record);
                System.out.println("Sent: " + message);

                // Sleep to simulate real-time streaming
                TimeUnit.MILLISECONDS.sleep(100);
            }
        } catch (InterruptedException e) {
            e.printStackTrace();
        } finally {
