import org.apache.flink.api.common.functions.FlatMapFunction;
import org.apache.flink.api.common.serialization.SimpleStringSchema;
import org.apache.flink.streaming.api.datastream.DataStream;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import org.apache.flink.util.Collector;
import org.apache.flink.shaded.jackson2.com.fasterxml.jackson.databind.ObjectMapper;

import java.util.Properties;

public class FlinkInteractionProcessor {

    private static final String KAFKA_TOPIC = "user-interactions";
    private static final String KAFKA_BROKERS = "localhost:9092";

    public static void main(String[] args) throws Exception {
        StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        Properties properties = new Properties();
        properties.setProperty("bootstrap.servers", KAFKA_BROKERS);
        properties.setProperty("group.id", "flink-group");

        FlinkKafkaConsumer<String> consumer = new FlinkKafkaConsumer<>(
                KAFKA_TOPIC, new SimpleStringSchema(), properties);

        DataStream<String> stream = env.addSource(consumer);

        DataStream<UserInteraction> interactions = stream.flatMap(new InteractionParser());

        interactions.keyBy(UserInteraction::getUserId)
                .flatMap(new InteractionAggregator())
                .print();

        env.execute("Flink Interaction Processor");
    }

    public static class InteractionParser implements FlatMapFunction<String, UserInteraction> {
        private static final ObjectMapper mapper = new ObjectMapper();

        @Override
        public void flatMap(String value, Collector<UserInteraction> out) {
            try {
                UserInteraction interaction = mapper.readValue(value, UserInteraction.class);
                out.collect(interaction);
            } catch (Exception e) {
                e.printStackTrace();
            }
        }
    }

    public static class InteractionAggregator implements FlatMapFunction<UserInteraction, String> {
        private static final long serialVersionUID = 1L;

        @Override
        public void flatMap(UserInteraction interaction, Collector<String> out) {
            // Aggregate interaction data (e.g., count, type stats)
            // This example simply prints interactions
            out.collect("Aggregated interaction for user: " + interaction.getUserId());
        }
    }

    public static class UserInteraction {
        private String userId;
        private String interaction;

        // Getters and setters

        public String getUserId() {
            return userId;
        }

        public void setUserId(String userId) {
            this.userId = userId;
        }

        public String getInteraction() {
            return interaction;
        }

        public void setInteraction(String interaction) {
            this.interaction = interaction;
        }
    }
}

