# compliance_checker.py

import nltk
from nltk.corpus import stopwords
from nltk.tokenize import word_tokenize
import jsonschema
from jsonschema import validate

# Downloading necessary NLTK data
nltk.download('punkt')
nltk.download('stopwords')

class ComplianceChecker:
    def __init__(self):
        self.stop_words = set(stopwords.words('english'))
        # Sample schema for ad compliance
        self.schema = {
            "type": "object",
            "properties": {
                "ad_text": {"type": "string"},
                "metadata": {"type": "object"}
            },
            "required": ["ad_text"]
        }

    def validate_schema(self, ad_data):
        try:
            validate(instance=ad_data, schema=self.schema)
            return True
        except jsonschema.exceptions.ValidationError as err:
            print(f"Schema validation error: {err}")
            return False

    def is_compliant(self, ad_text):
        # Tokenize and filter stop words
        word_tokens = word_tokenize(ad_text)
        filtered_text = [w for w in word_tokens if not w.lower() in self.stop_words]

        # Rule-based compliance check
        prohibited_words = {"explicit", "prohibited", "banned"}
        for word in filtered_text:
            if word.lower() in prohibited_words:
                print(f"Ad contains prohibited word: {word}")
                return False

        return True

    def check_ad_compliance(self, ad_data):
        if not self.validate_schema(ad_data):
            return False

        ad_text = ad_data['ad_text']
        return self.is_compliant(ad_text)

