# Index name for storing ad revenue data
index_name = 'ad_revenue'

def create_index():
    """Create an Elasticsearch index with the appropriate mapping."""
    if not es.indices.exists(index=index_name):
        logging.info(f"Creating index: {index_name}")
        es.indices.create(index=index_name, body={
            "mappings": {
                "properties": {
                    "timestamp": {"type": "date"},
                    "ad_id": {"type": "keyword"},
                    "user_id": {"type": "keyword"},
                    "revenue": {"type": "float"},
                    "platform": {"type": "keyword"},
                    "region": {"type": "keyword"}
                }
            }
        })

def generate_sample_data(num_records=1000):
    """Generate sample ad revenue data."""
    platforms = ['OnlyFans', 'Patreon', 'CustomSite']
    regions = ['North America', 'Europe', 'Asia']
    data = []
    for _ in range(num_records):
        record = {
            "timestamp": datetime.now().isoformat(),
            "ad_id": f"ad_{random.randint(1, 100)}",
            "user_id": f"user_{random.randint(1, 500)}",
            "revenue": round(random.uniform(0.5, 50.0), 2),
            "platform": random.choice(platforms),
            "region": random.choice(regions)
        }
        data.append(record)
    return data

def ingest_data(data):
    """Ingest data into Elasticsearch."""
    try:
        logging.info(f"Ingesting {len(data)} records into index: {index_name}")
        helpers.bulk(es, data, index=index_name)
    except Exception as e:
        logging.error(f"Failed to ingest data: {str(e)}")

if __name__ == '__main__':
    create_index()
    sample_data = generate_sample_data()
    ingest_data(sample_data)

