from elasticsearch import Elasticsearch
from datetime import datetime, timedelta
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Elasticsearch configuration
es_host = 'http://localhost:9200'
es = Elasticsearch([es_host])

# Index name for ad revenue data
index_name = 'ad_revenue'

def get_top_ads(time_window='1h'):
    """Get top performing ads in the last `time_window`."""
    # Define the time range for the query
    end_time = datetime.now()
    start_time = end_time - timedelta(hours=int(time_window[:-1]))

    # Elasticsearch query to aggregate revenue by ad_id
    query = {
        "query": {
            "range": {
                "timestamp": {
                    "gte": start_time.isoformat(),
                    "lte": end_time.isoformat()
                }
            }
        },
        "aggs": {
            "top_ads": {
                "terms": {
                    "field": "ad_id",
                    "size": 5,
                    "order": {"total_revenue": "desc"}
                },
                "aggs": {
                    "total_revenue": {
                        "sum": {"field": "revenue"}
                    }
                }
            }
        }
    }

    try:
        logging.info(f"Fetching top ads from {start_time} to {end_time}")
        response = es.search(index=index_name, body=query)
        top_ads = response['aggregations']['top_ads']['buckets']
        logging.info("Top Ads:")
        for ad in top_ads:
            logging.info(f"Ad ID: {ad['key']}, Total Revenue: {ad['total_revenue']['value']}")
    except Exception as e:
        logging.error(f"Error fetching top ads: {str(e)}")

if __name__ == '__main__':
    get_top_ads()

