    private final BidStrategy bidStrategy;
    private final RestTemplate restTemplate;

    @Autowired
    public AuctionService(BidStrategy bidStrategy) {
        this.bidStrategy = bidStrategy;
        this.restTemplate = new RestTemplate();
    }

    /**
     * Participate in an ad auction by submitting a bid.
     * @param auctionId The ID of the auction to participate in.
     * @param userId The ID of the user for personalized bidding.
     * @return The result of the auction participation.
     */
    public String participateInAuction(String auctionId, String userId) {
        try {
            double bidAmount = bidStrategy.calculateBid(auctionId, userId);

            String auctionEndpoint = "https://api.adplatform.com/auctions/" + auctionId + "/bid";
            String response = restTemplate.postForObject(auctionEndpoint, bidAmount, String.class);

            return handleAuctionResponse(response);
        } catch (Exception e) {
            // Log error and return failure message
            System.err.println("Error participating in auction: " + e.getMessage());
            return "Failed to participate in auction.";
        }
    }

    /**
     * Handle the response from the auction platform.
     * @param response The response string from the auction API.
     * @return A message indicating the outcome of the auction.
     */
    private String handleAuctionResponse(String response) {
        // Parse and process the response (e.g., JSON parsing)
        // For illustration, assume the response is a simple string
        if (response.contains("success")) {
            return "Successfully placed a bid.";
        } else {
            return "Bid not successful.";
        }
    }
}

