import { useEffect } from 'react';
import * as d3 from 'd3';

/**
 * useD3 - Custom hook for integrating D3.js with React
 * 
 * @param {Object} svgRef - Ref to the SVG element
 * @param {Array} data - Data for the chart
 * @param {number} width - Width of the chart
 * @param {number} height - Height of the chart
 */
const useD3 = (svgRef, data, width, height) => {
  useEffect(() => {
    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove(); // Clear previous content

    // Set margins and dimensions
    const margin = { top: 20, right: 30, bottom: 40, left: 40 };
    const innerWidth = width - margin.left - margin.right;
    const innerHeight = height - margin.top - margin.bottom;

    // Create scales
    const xScale = d3.scaleBand()
      .domain(data.map(d => d.date))
      .range([0, innerWidth])
      .padding(0.1);

    const yScale = d3.scaleLinear()
      .domain([0, d3.max(data, d => d.clicks)])
      .nice()
      .range([innerHeight, 0]);

    // Append group element and transform
    const g = svg.append('g')
      .attr('transform', `translate(${margin.left},${margin.top})`);

    // X-axis
    g.append('g')
      .call(d3.axisBottom(xScale))
      .attr('transform', `translate(0,${innerHeight})`)
      .selectAll('text')
      .attr('transform', 'rotate(-45)')
      .style('text-anchor', 'end');

    // Y-axis
    g.append('g')
      .call(d3.axisLeft(yScale));

    // Bars
    g.selectAll('.bar')
      .data(data)
      .enter().append('rect')
      .attr('class', 'bar')
      .attr('x', d => xScale(d.date))
      .attr('y', d => yScale(d.clicks))
      .attr('width', xScale.bandwidth())
      .attr('height', d => innerHeight - yScale(d.clicks))
      .on('mouseover', (event, d) => {
        const tooltip = d3.select('.tooltip');
        tooltip.style('opacity', 1);
        tooltip.html(`Clicks: ${d.clicks}<br>Views: ${d.views}<br>Revenue: $${d.revenue}`)
          .style('left', `${event.pageX}px`)
          .style('top', `${event.pageY - 28}px`);
      })
      .on('mouseout', () => {
        d3.select('.tooltip').style('opacity', 0);
      });

    // Tooltip
    const tooltip = d3.select('body').append('div')
      .attr('class', 'tooltip')
      .style('opacity', 0);

    return () => {
      tooltip.remove(); // Clean up the tooltip
    };

  }, [data, width, height, svgRef]);
};

export default useD3;

