using UnityEngine;
using UnityEngine.XR.ARFoundation;
using UnityEngine.XR.ARSubsystems;

/// <summary>
/// This script configures the AR session and initializes the AR Foundation components.
/// </summary>
public class SetupAR : MonoBehaviour
{
    [SerializeField] private ARSession arSession;
    [SerializeField] private ARPlaneManager arPlaneManager;

    void Start()
    {
        // Check if AR is supported on the device
        if (ARSession.state == ARSessionState.None || ARSession.state == ARSessionState.CheckingAvailability)
        {
            StartCoroutine(CheckARSupport());
        }
        else
        {
            // Initialize AR components
            InitializeAR();
        }
    }

    private System.Collections.IEnumerator CheckARSupport()
    {
        yield return ARSession.CheckAvailability();

        if (ARSession.state == ARSessionState.NeedsInstall)
        {
            // Prompt user to install AR software
            yield return ARSession.Install();
        }

        if (ARSession.state == ARSessionState.Ready)
        {
            // Initialize AR components
            InitializeAR();
        }
        else
        {
            Debug.LogError("AR is not supported on this device.");
        }
    }

    private void InitializeAR()
    {
        arSession.enabled = true;
        arPlaneManager.enabled = true;

        Debug.Log("AR Session and Plane Manager initialized.");
    }
}

