// Import necessary modules
const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const path = require('path');

// Initialize express app
const app = express();

// Serve static files for the client
app.use(express.static(path.join(__dirname, '../client')));

// Create HTTP server and bind with express app
const server = http.createServer(app);

// Initialize Socket.IO for WebSocket communication
const io = socketIo(server, {
  cors: {
    origin: "*", // Allow all origins for simplicity; restrict in production
    methods: ["GET", "POST"]
  }
});

// Handle WebSocket connections
io.on('connection', (socket) => {
  console.log('New client connected:', socket.id);

  // Relay 'offer' message from one client to another
  socket.on('offer', (data) => {
    socket.to(data.target).emit('offer', {
      sdp: data.sdp,
      sender: socket.id
    });
  });

  // Relay 'answer' message from one client to another
  socket.on('answer', (data) => {
    socket.to(data.target).emit('answer', {
      sdp: data.sdp,
      sender: socket.id
    });
  });

  // Relay 'candidate' messages for ICE candidate exchange
  socket.on('candidate', (data) => {
    socket.to(data.target).emit('candidate', {
      candidate: data.candidate,
      sender: socket.id
    });
  });

  // Handle client disconnection
  socket.on('disconnect', () => {
    console.log('Client disconnected:', socket.id);
    socket.broadcast.emit('user-disconnected', socket.id);
  });
});

// Start the server
const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
