// Initialize Socket.IO client
const socket = io();

// Get video elements from the DOM
const localVideo = document.getElementById('localVideo');
const remoteVideo = document.getElementById('remoteVideo');

// Configuration for WebRTC connection
const configuration = {
  iceServers: [
    { urls: 'stun:stun.l.google.com:19302' }
  ]
};

// Peer connection object
let localStream;
let peerConnection;

// Start capturing local video and audio
navigator.mediaDevices.getUserMedia({ video: true, audio: true })
  .then(stream => {
    localVideo.srcObject = stream;
    localStream = stream;

    // Initialize peer connection
    peerConnection = new RTCPeerConnection(configuration);

    // Add local stream tracks to the peer connection
    localStream.getTracks().forEach(track => peerConnection.addTrack(track, localStream));

    // Handle incoming remote stream
    peerConnection.ontrack = event => {
      remoteVideo.srcObject = event.streams[0];
    };

    // ICE candidate gathering
    peerConnection.onicecandidate = event => {
      if (event.candidate) {
        socket.emit('candidate', {
          candidate: event.candidate,
          target: 'target-client-id' // Replace with actual target client ID
        });
      }
    };

    // Create an offer to initiate connection
    peerConnection.createOffer()
      .then(offer => {
        return peerConnection.setLocalDescription(offer);
      })
      .then(() => {
        socket.emit('offer', {
          sdp: peerConnection.localDescription,
          target: 'target-client-id' // Replace with actual target client ID
        });
      });
  })
  .catch(error => {
    console.error('Error accessing media devices.', error);
  });

// Handle incoming offer
socket.on('offer', (data) => {
  peerConnection.setRemoteDescription(new RTCSessionDescription(data.sdp))
    .then(() => peerConnection.createAnswer())
    .then(answer => peerConnection.setLocalDescription(answer))
    .then(() => {
      socket.emit('answer', {
        sdp: peerConnection.localDescription,
        target: data.sender
      });
    });
});

// Handle incoming answer
socket.on('answer', (data) => {
  peerConnection.setRemoteDescription(new RTCSessionDescription(data.sdp));
});

// Handle incoming ICE candidates
socket.on('candidate', (data) => {
  peerConnection.addIceCandidate(new RTCIceCandidate(data.candidate))
    .catch(e => console.error('Error adding received ICE candidate', e));
});

