const mongoose = require('mongoose');

const interactionSchema = new mongoose.Schema({
  eventId: String,
  votes: Map,
  questions: [String],
});

interactionSchema.statics.recordVote = async function (eventId, option) {
  const interaction = await this.findOne({ eventId });
  if (!interaction) {
    const newInteraction = new this({ eventId, votes: { [option]: 1 } });
    await newInteraction.save();
  } else {
    interaction.votes.set(option, (interaction.votes.get(option) || 0) + 1);
    await interaction.save();
  }
};

interactionSchema.statics.getPollResults = async function (eventId) {
  const interaction = await this.findOne({ eventId });
  return interaction ? interaction.votes : {};
};

interactionSchema.statics.addQuestion = async function (eventId, question) {
  const interaction = await this.findOne({ eventId });
  if (!interaction) {
    const newInteraction = new this({ eventId, questions: [question] });
    await newInteraction.save();
  } else {
    interaction.questions.push(question);
    await interaction.save();
  }
};

interactionSchema.statics.getQuestions = async function (eventId) {
  const interaction = await this.findOne({ eventId });
  return interaction ? interaction.questions : [];
};

module.exports = mongoose.model('Interaction', interactionSchema);

