    const userId = auth.currentUser.uid;
    const response = await axios.post('/api/purchase', { userId, itemID, quantity });

    if (response.data.success) {
      // Update user's inventory in Firebase
      const inventoryRef = db.ref(`users/${userId}/inventory`);
      inventoryRef.transaction(currentInventory => {
        if (currentInventory) {
          if (!currentInventory[itemID]) {
            currentInventory[itemID] = 0;
          }
          currentInventory[itemID] += quantity;
        }
        return currentInventory;
      });
      return { success: true, message: "Purchase successful!" };
    } else {
      return { success: false, message: "Purchase failed!" };
    }
  } catch (error) {
    console.error("Error during purchase:", error);
    return { success: false, message: "An error occurred during the purchase." };
