import org.apache.flink.api.scala._
import org.apache.flink.streaming.api.scala.StreamExecutionEnvironment
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer
import org.apache.flink.streaming.util.serialization.SimpleStringSchema
import java.util.Properties

object FlinkProcessingJob {
  def main(args: Array[String]): Unit = {
    val env = StreamExecutionEnvironment.getExecutionEnvironment

    // Kafka consumer configuration
    val properties = new Properties()
    properties.setProperty("bootstrap.servers", "localhost:9092")
    properties.setProperty("group.id", "flink_consumer_group")

    // Create Kafka consumer
    val kafkaConsumer = new FlinkKafkaConsumer[String](
      "event_data",
      new SimpleStringSchema(),
      properties
    )

    // Add Kafka source to Flink environment
    val eventStream = env.addSource(kafkaConsumer)

    // Process stream and compute metrics
    val processedStream = eventStream
      .map { record =>
        val event = parseEvent(record)
        (event.eventType, event.amount)
      }
      .keyBy(_._1)
      .sum(1)

    // Print processed stream to console (or send to another sink)
    processedStream.print()

    // Execute Flink job
    env.execute("Flink Kafka Processing Job")
  }

  // Function to parse JSON string to Event object
  case class Event(eventType: String, amount: Double)

  def parseEvent(record: String): Event = {
    // Simple JSON parsing (assuming record is valid JSON)
    val data = io.circe.parser.parse(record).getOrElse(Json.Null)
    val eventType = data.hcursor.get[String]("event_type").getOrElse("unknown")
    val amount = data.hcursor.get[Double]("amount").getOrElse(0.0)
    Event(eventType, amount)
  }
}

