        return jsonify({'status': 'success'}), 200
    except ValueError as e:
        # Invalid payload
        print('Invalid payload')
        abort(400)
    except stripe.error.SignatureVerificationError as e:
        # Invalid signature
        print('Invalid signature')
        abort(400)

if __name__ == '__main__':
    app.run(port=4242)

