const connectRabbitMQ = require('../config/rabbitmq');
const postToFacebook = require('../connectors/facebookConnector');
const postToTwitter = require('../connectors/twitterConnector');
const postToYouTube = require('../connectors/youtubeConnector');
const postToTikTok = require('../connectors/tiktokConnector');

async function startDistributionService() {
    const channel = await connectRabbitMQ();

    channel.consume('content_distribution', async (msg) => {
        if (msg !== null) {
            const content = JSON.parse(msg.content.toString());

            // Posting to all platforms
            await Promise.all([
                postToFacebook(content),
                postToTwitter(content),
                postToYouTube(content),
                postToTikTok(content)
            ]);

            // Acknowledge the message after processing
            channel.ack(msg);
        }
    }, { noAck: false });

    console.log("Distribution Service Started");
}

startDistributionService().catch(console.error);

