using UnityEngine;
using UnityEngine.XR;

public class DeviceProfileManager : MonoBehaviour
{
    private void Start()
    {
        // Detect device specifications
        DetectDeviceSpecifications();

        // Adjust quality settings based on the device
        AdjustQualitySettings();
    }

    private void DetectDeviceSpecifications()
    {
        // Use XRDevice API to get device model and capabilities
        string deviceModel = SystemInfo.deviceModel;
        bool isARCapable = XRSettings.isDeviceActive;

        Debug.Log($"Device Model: {deviceModel}");
        Debug.Log($"AR Capable: {isARCapable}");

        // Additional device information (like GPU, RAM)
        int systemMemorySize = SystemInfo.systemMemorySize;
        string graphicsDeviceName = SystemInfo.graphicsDeviceName;

        Debug.Log($"System Memory: {systemMemorySize} MB");
        Debug.Log($"Graphics Device: {graphicsDeviceName}");
    }

    private void AdjustQualitySettings()
    {
        // Example condition to adjust quality settings
        if (SystemInfo.systemMemorySize < 4000)
        {
            QualitySettings.SetQualityLevel(0, true); // Set to lowest quality
            Debug.Log("Quality set to Low due to limited memory.");
        }
        else
        {
            QualitySettings.SetQualityLevel(5, true); // Set to high quality
            Debug.Log("Quality set to High.");
        }
    }
}

