using UnityEngine;

/// <summary>
/// QualityManager dynamically adjusts the quality settings based on device specifications.
/// </summary>
public class QualityManager : MonoBehaviour
{
    // Target frame rate for smooth performance
    private const int targetFrameRate = 60;

    // Minimum and maximum quality levels as defined in Unity's Quality Settings
    private const int minQualityLevel = 0;
    private const int maxQualityLevel = 5;

    // Device performance thresholds
    private const int minCPUCores = 4;
    private const int minGPUMemoryMB = 2048; // 2GB

    void Start()
    {
        // Set the target frame rate
        Application.targetFrameRate = targetFrameRate;

        // Adjust quality settings based on device specifications at startup
        AdjustQualitySettings();
    }

    /// <summary>
    /// Adjusts the quality settings based on the device's hardware specifications.
    /// </summary>
    private void AdjustQualitySettings()
    {
        // Retrieve device specifications
        int cpuCores = SystemInfo.processorCount;
        int gpuMemory = SystemInfo.graphicsMemorySize; // In megabytes

        // Determine the appropriate quality level
        int qualityLevel = CalculateQualityLevel(cpuCores, gpuMemory);

        // Set the quality level
        QualitySettings.SetQualityLevel(qualityLevel, true);

        // Log the quality adjustment
        Debug.Log($"QualityManager: Set quality level to {qualityLevel} based on device specs.");
    }

    /// <summary>
    /// Calculates the quality level based on CPU cores and GPU memory.
    /// </summary>
    /// <param name="cpuCores">Number of CPU cores.</param>
    /// <param name="gpuMemory">Amount of GPU memory in MB.</param>
    /// <returns>Calculated quality level.</returns>
    private int CalculateQualityLevel(int cpuCores, int gpuMemory)
    {
        // Basic profiling logic
        if (cpuCores >= minCPUCores && gpuMemory >= minGPUMemoryMB)
        {
            // High-end devices
            return maxQualityLevel;
        }
        else if (cpuCores >= minCPUCores / 2 && gpuMemory >= minGPUMemoryMB / 2)
        {
            // Mid-range devices
            return maxQualityLevel - 2;
        }
        else
        {
            // Low-end devices
            return minQualityLevel;
        }
    }

    void Update()
    {
        // Monitor performance and adjust quality settings at runtime if necessary
        MonitorPerformance();
    }

    /// <summary>
    /// Monitors the application's performance and adjusts quality settings if needed.
    /// </summary>
    private void MonitorPerformance()
    {
        // Simple frame rate monitoring and adjustment
        if (Time.frameCount % 60 == 0) // Check every second
        {
            if (Application.targetFrameRate > 0 && Time.deltaTime > 1.0f / targetFrameRate)
            {
                // If the frame rate is below the target, consider lowering the quality level
                int currentQualityLevel = QualitySettings.GetQualityLevel();
                if (currentQualityLevel > minQualityLevel)
                {
                    QualitySettings.DecreaseLevel(true);
                    Debug.Log("QualityManager: Decreased quality level to improve performance.");
                }
            }
            else if (Application.targetFrameRate > 0 && Time.deltaTime < 1.0f / (targetFrameRate + 10))
            {
                // If the frame rate is comfortably above the target, consider increasing the quality level
                int currentQualityLevel = QualitySettings.GetQualityLevel();
                if (currentQualityLevel < maxQualityLevel)
                {
                    QualitySettings.IncreaseLevel(true);
                    Debug.Log("QualityManager: Increased quality level to enhance graphics.");
                }
            }
        }
    }
}

