// server.js
const WebSocket = require('ws');
const server = new WebSocket.Server({ port: 8080 });

let clients = [];

server.on('connection', (ws) => {
  console.log('New client connected');
  clients.push(ws);

  // Send a welcome message to the new client
  ws.send(JSON.stringify({ type: 'welcome', message: 'Welcome to the AR Experience Platform' }));

  // Handle incoming messages from clients
  ws.on('message', (message) => {
    console.log('Received:', message);
    // Here you could handle messages, e.g., client requests for specific content updates
  });

  // Handle client disconnection
  ws.on('close', () => {
    console.log('Client disconnected');
    clients = clients.filter(client => client !== ws);
  });

  // Handle errors
  ws.on('error', (error) => {
    console.error('WebSocket error:', error);
  });
});

// Function to broadcast updates to all connected clients
function broadcastUpdate(contentUpdate) {
  clients.forEach(client => {
    if (client.readyState === WebSocket.OPEN) {
      client.send(JSON.stringify({ type: 'content-update', data: contentUpdate }));
    }
  });
}

// Example function to simulate content updates every 10 seconds
setInterval(() => {
  const contentUpdate = {
    timestamp: new Date(),
    content: 'New AR content available!', // This would be the new content data
  };

  console.log('Broadcasting content update:', contentUpdate);
  broadcastUpdate(contentUpdate);
}, 10000);

console.log('WebSocket server is running on ws://localhost:8080');

